module RefModule(
    input       clk,
    input       rst,
    output reg [3:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge rst) begin
        if(rst) begin
            count <= 4'b0000;
        end
        else begin
            count <= count + 1;
        end
    end

endmodule
